    {"code": "CT.DP-P5", "name": "Attribute references are substituted for attribute values.", "description": ""},
    {"code": "CM.PO-P1", "name": "Transparency policies, processes, and procedures for communicating data processing purposes, practices, and associated privacy risks are established and in place.", "description": ""},
    {"code": "CM.PO-P2", "name": "Roles and responsibilities (e.g., public relations) for communicating data processing purposes, practices, and associated privacy risks are established.", "description": ""},
    {"code": "CM.AW-P1", "name": "Mechanisms (e.g., notices, internal or public reports) for communicating data processing purposes, practices, associated privacy risks, and options for enabling individuals' data processing preferences and requests are established and in place.", "description": ""},
    {"code": "CM.AW-P2", "name": "Mechanisms for obtaining feedback from individuals (e.g., surveys or focus groups) about data processing and associated privacy risks are established and in place.", "description": ""},
    {"code": "CM.AW-P3", "name": "System/product/service design enables data processing visibility.", "description": ""},
    {"code": "CM.AW-P4", "name": "Records of data disclosures and sharing are maintained and can be accessed for review or transmission/disclosure.", "description": ""},
    {"code": "CM.AW-P5", "name": "Data corrections or deletions can be communicated to individuals or organizations (e.g., data sources) in the data processing ecosystem.", "description": ""},
    {"code": "CM.AW-P6", "name": "Data provenance and lineage are maintained and can be accessed for review or transmission/disclosure.", "description": ""},
    {"code": "CM.AW-P7", "name": "Impacted individuals and organizations are notified about a privacy breach or event.", "description": ""},
    {"code": "CM.AW-P8", "name": "Individuals are provided with mitigation mechanisms (e.g., credit monitoring, consent withdrawal, data alteration or deletion) to address impacts of problematic data actions.", "description": ""},
    {"code": "PR.PO-P1", "name": "A baseline configuration of information technology is created and maintained incorporating security principles (e.g., concept of least functionality).", "description": ""},
    {"code": "PR.PO-P2", "name": "Configuration change control processes are established and in place.", "description": ""},
    {"code": "PR.PO-P3", "name": "Backups of information are conducted, maintained, and tested.", "description": ""},
    {"code": "PR.PO-P4", "name": "Policy and regulations regarding the physical operating environment for organizational assets are met.", "description": ""},
    {"code": "PR.PO-P5", "name": "Protection processes are improved.", "description": ""},
    {"code": "PR.PO-P6", "name": "Effectiveness of protection technologies is shared.", "description": ""},
    {"code": "PR.PO-P7", "name": "Response plans (Incident Response and Business Continuity) and recovery plans (Incident Recovery and Disaster Recovery) are established, in place, and managed.", "description": ""},
    {"code": "PR.PO-P8", "name": "Response and recovery plans are tested.", "description": ""},
    {"code": "PR.PO-P9", "name": "Privacy procedures are included in human resources practices (e.g., deprovisioning, personnel screening).", "description": ""},
    {"code": "PR.PO-P10", "name": "A vulnerability management plan is developed and implemented.", "description": ""},
    {"code": "PR.AC-P1", "name": "Identities and credentials are issued, managed, verified, revoked, and audited for authorized individuals, processes, and devices.", "description": ""},
    {"code": "PR.AC-P2", "name": "Physical access to data and devices is managed.", "description": ""},
    {"code": "PR.AC-P3", "name": "Remote access is managed.", "description": ""},
    {"code": "PR.AC-P4", "name": "Access permissions and authorizations are managed, incorporating the principles of least privilege and separation of duties.", "description": ""},
    {"code": "PR.AC-P5", "name": "Network integrity is protected (e.g., network segregation, network segmentation).", "description": ""},
    {"code": "PR.AC-P6", "name": "Individuals and devices are proofed and bound to credentials, and authenticated commensurate with the risk of the transaction (e.g., individuals' security and privacy risks and other organizational risks).", "description": ""},
    {"code": "PR.DS-P1", "name": "Data-at-rest are protected.", "description": ""},
    {"code": "PR.DS-P2", "name": "Data-in-transit are protected.", "description": ""},
    {"code": "PR.DS-P3", "name": "Systems/products/services and associated data are formally managed throughout removal, transfers, and disposition.", "description": ""},
    {"code": "PR.DS-P4", "name": "Adequate capacity to ensure availability is maintained.", "description": ""},
    {"code": "PR.DS-P5", "name": "Protections against data leaks are implemented.", "description": ""},
    {"code": "PR.DS-P6", "name": "Integrity checking mechanisms are used to verify software, firmware, and information integrity.", "description": ""},
    {"code": "PR.DS-P7", "name": "The development and testing environment(s) are separate from the production environment.", "description": ""},
    {"code": "PR.DS-P8", "name": "Integrity checking mechanisms are used to verify hardware integrity.", "description": ""},
    {"code": "PR.MA-P1", "name": "Maintenance and repair of organizational assets are performed and logged, with approved and controlled tools.", "description": ""},
    {"code": "PR.MA-P2", "name": "Remote maintenance of organizational assets is approved, logged, and performed in a manner that prevents unauthorized access.", "description": ""},
