def get_control_set_templates() -> List[ControlSetTemplate]:
    """Returns all available control set templates"""
    return CONTROL_SET_TEMPLATES

def get_control_set_by_name(name: str) -> ControlSetTemplate | None:
    """Get a specific control set template by name"""
    for template in CONTROL_SET_TEMPLATES:
        if template["name"] == name:
            return template
    return None

def get_available_control_sets() -> List[Dict[str, str]]:
    """Returns a summary list of available control sets (name and description only)"""
    return [
        {
            "name": template["name"],
            "description": template["description"],
            "control_count": len(template["controls"])
        }
        for template in CONTROL_SET_TEMPLATES
    ]
